        const appearanceFile = this.getConfigFile("appearance");
        let changed = false;

        try {
          const stat = await this.adapter.stat(appFile);
          if (stat.mtime > this.configTs) changed = true;
        } catch {
          changed = true;
        }

        // 检查 appearance 是否更新
        try {
          const stat = await this.adapter.stat(appearanceFile);
          if (stat.mtime > this.configTs) changed = true;
        } catch {
          changed = true;
        }

